import { createClient } from "@/lib/supabase/server";
import { redirect } from "next/navigation";
import { formatBRL, formatDate } from "@/lib/utils";
import type { Metadata } from "next";

export const metadata: Metadata = { title: "Financeiro" };

export default async function FinanceiroPage() {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) redirect("/auth/login");

  const { data: therapist } = await supabase
    .from("therapists")
    .select("id, session_price")
    .eq("user_id", user.id)
    .single();
  if (!therapist) redirect("/auth/login");

  const now = new Date();
  const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1).toISOString();
  const lastMonthStart = new Date(now.getFullYear(), now.getMonth() - 1, 1).toISOString();
  const lastMonthEnd = new Date(now.getFullYear(), now.getMonth(), 0).toISOString();

  const [paymentsThisMonth, paymentsLastMonth, allPayments] = await Promise.all([
    supabase
      .from("payments")
      .select("amount, status")
      .eq("therapist_id", therapist.id)
      .eq("status", "paid")
      .gte("created_at", startOfMonth),
    supabase
      .from("payments")
      .select("amount")
      .eq("therapist_id", therapist.id)
      .eq("status", "paid")
      .gte("created_at", lastMonthStart)
      .lte("created_at", lastMonthEnd),
    supabase
      .from("payments")
      .select(`
        id, amount, currency, method, status, created_at, paid_at,
        patient:patients(name)
      `)
      .eq("therapist_id", therapist.id)
      .order("created_at", { ascending: false })
      .limit(50),
  ]);

  const mrr = (paymentsThisMonth.data ?? []).reduce(
    (acc, p) => acc + Number(p.amount),
    0
  );
  const mrrLast = (paymentsLastMonth.data ?? []).reduce(
    (acc, p) => acc + Number(p.amount),
    0
  );
  const mrrDelta = mrrLast > 0 ? ((mrr - mrrLast) / mrrLast) * 100 : 0;
  const payments = allPayments.data ?? [];
  const totalPaid = payments
    .filter((p) => p.status === "paid")
    .reduce((acc, p) => acc + Number(p.amount), 0);
  const pending = payments.filter((p) => p.status === "pending").length;

  const PAYMENT_STATUS_CONFIG: Record<string, { label: string; badgeClass: string }> = {
    pending: {
      label: "Pendente",
      badgeClass: "border-[#fbbf24]/40 bg-[#fbbf24]/10 text-[#fbbf24]",
    },
    processing: {
      label: "Processando",
      badgeClass: "border-[#38bdf8]/40 bg-[#38bdf8]/10 text-[#38bdf8]",
    },
    paid: {
      label: "Pago",
      badgeClass:
        "border-[rgba(82,183,136,.4)] bg-[rgba(82,183,136,.12)] text-[var(--color-brand)]",
    },
    failed: {
      label: "Falhou",
      badgeClass: "border-[#f87171]/40 bg-[#f87171]/10 text-[#f87171]",
    },
    refunded: {
      label: "Reembolsado",
      badgeClass: "border-[#a78bfa]/40 bg-[#a78bfa]/10 text-[#a78bfa]",
    },
    disputed: {
      label: "Disputado",
      badgeClass: "border-[#f87171]/40 bg-[#f87171]/10 text-[#f87171]",
    },
  };

  const METHOD_LABELS: Record<string, string> = {
    stripe: "Stripe",
    pix: "PIX",
    manual: "Manual",
    exempt: "Isento",
  };

  const isPositive = mrrDelta >= 0;

  return (
    <div className="p-8 max-w-6xl mx-auto w-full animate-[fadeUp_.4s_ease-out_both]">
      {/* Header */}
      <div className="mb-8">
        <h1 className="font-[family-name:var(--font-display)] text-4xl font-light text-[var(--color-text-primary)] tracking-tight">
          Financeiro
        </h1>
        <p className="text-[14px] text-[var(--color-text-muted)] mt-1 font-light">
          Receitas, pagamentos e relatórios financeiros
        </p>
      </div>

      {/* KPI cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
        <div className="bg-[var(--color-surface)] border border-[var(--color-border-subtle)] rounded-2xl p-6 glass-panel relative overflow-hidden group hover:border-[var(--color-border-strong)] transition-all duration-300">
          <div className="absolute top-0 right-0 w-32 h-32 bg-[#fbbf24] opacity-[0.03] rounded-bl-full group-hover:opacity-[0.06] transition-opacity duration-500 pointer-events-none" />
          
          <div className="text-[12px] text-[var(--color-text-muted)] uppercase tracking-widest font-medium mb-2 relative z-10">
            MRR Este Mês
          </div>
          <div className="font-[family-name:var(--font-display)] text-[32px] font-light text-[#fbbf24] leading-tight mb-2 tracking-tight relative z-10">
            {formatBRL(mrr)}
          </div>
          <div className={`text-[12px] font-medium relative z-10 flex items-center gap-1 ${isPositive ? "text-[var(--color-brand)]" : "text-[#f87171]"}`}>
            <span className="text-[14px]">{isPositive ? "↑" : "↓"}</span> {Math.abs(mrrDelta).toFixed(1)}% vs mês anterior
          </div>
        </div>

        <KPISimple
          label="Total Recebido"
          value={formatBRL(totalPaid)}
          tone="brand"
          delay={0.05}
        />
        <KPISimple
          label="Pagamentos"
          value={String(payments.length)}
          tone="sky"
          delay={0.1}
        />
        <KPISimple
          label="Pendentes"
          value={String(pending)}
          tone="amber"
          delay={0.15}
        />
      </div>

      {/* Price info */}
      <div className="bg-[var(--color-surface)] border border-[var(--color-border-subtle)] rounded-2xl p-5 mb-8 flex items-center gap-3 w-fit animate-[fadeUp_.4s_ease-out_.2s_both] glass-panel shadow-sm">
        <span className="text-[11px] text-[var(--color-text-muted)] uppercase tracking-widest font-medium">
          Preço padrão por sessão:
        </span>
        <span className="font-[family-name:var(--font-display)] text-[20px] font-light text-[#fbbf24]">
          {formatBRL(Number(therapist.session_price))}
        </span>
      </div>

      {/* Payments table */}
      <div className="bg-[var(--color-surface)] border border-[var(--color-border-subtle)] rounded-2xl overflow-hidden glass-panel animate-[fadeUp_.4s_ease-out_.25s_both]">
        <div className="px-6 py-5 border-b border-[var(--color-border-subtle)] bg-[var(--color-surface)]/50">
          <h2 className="font-[family-name:var(--font-display)] text-[22px] font-light text-[var(--color-text-primary)]">
            Últimos Pagamentos
          </h2>
        </div>

        {/* Table header */}
        <div className="hidden md:grid grid-cols-[2fr_1fr_1fr_1fr_1fr] px-6 py-4 border-b border-[var(--color-border-subtle)] text-[12px] text-[var(--color-text-muted)] uppercase tracking-widest font-medium bg-[var(--color-surface)]/30">
          <span>Paciente</span>
          <span>Data</span>
          <span>Valor</span>
          <span>Método</span>
          <span>Status</span>
        </div>

        {payments.length === 0 ? (
          <div className="px-10 py-16 text-center text-[var(--color-text-muted)] text-[14px] font-light">
            Nenhum pagamento registrado ainda.
          </div>
        ) : (
          <div className="flex flex-col">
            {payments.map((p, i) => {
              const patient = p.patient as unknown as { name: string } | null;
              const statusCfg = PAYMENT_STATUS_CONFIG[p.status] ?? {
                label: p.status,
                badgeClass:
                  "border-[var(--color-border-strong)] bg-[var(--color-surface-hover)] text-[var(--color-text-muted)]",
              };
              return (
                <div
                  key={p.id}
                  className={`grid grid-cols-2 md:grid-cols-[2fr_1fr_1fr_1fr_1fr] px-6 py-4 items-center gap-y-3 transition-colors hover:bg-[var(--color-surface-hover)] ${
                    i < payments.length - 1 ? "border-b border-[var(--color-border-subtle)]" : ""
                  }`}
                >
                  <span className="text-[14px] text-[var(--color-text-primary)] font-medium col-span-2 md:col-span-1">
                    {patient?.name ?? "—"}
                  </span>
                  <span className="text-[13px] text-[var(--color-text-secondary)] font-light">
                    <span className="md:hidden text-[var(--color-text-muted)] mr-2">Data:</span>
                    {formatDate(p.created_at)}
                  </span>
                  <span className="text-[15px] text-[var(--color-text-primary)] font-medium">
                    <span className="md:hidden text-[var(--color-text-muted)] text-[13px] font-normal mr-2">Valor:</span>
                    {formatBRL(Number(p.amount))}
                  </span>
                  <span className="text-[13px] text-[var(--color-text-secondary)] font-light">
                    <span className="md:hidden text-[var(--color-text-muted)] mr-2">Método:</span>
                    {p.method ? METHOD_LABELS[p.method] ?? p.method : "—"}
                  </span>
                  <div className="col-span-2 md:col-span-1">
                    <span
                      className={`text-[11px] px-3 py-1 rounded-full border inline-flex items-center w-fit font-medium ${statusCfg.badgeClass}`}
                    >
                      {statusCfg.label}
                    </span>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

function KPISimple({
  label,
  value,
  tone,
  delay = 0,
}: {
  label: string;
  value: string;
  tone: "brand" | "sky" | "amber";
  delay?: number;
}) {
  const delayClass: Record<string, string> = {
    "0": "[animation-delay:0s]",
    "0.05": "[animation-delay:0.05s]",
    "0.1": "[animation-delay:0.1s]",
    "0.15": "[animation-delay:0.15s]",
  };

  const toneClasses: Record<
    "brand" | "sky" | "amber",
    { glow: string; value: string }
  > = {
    brand: {
      glow: "bg-[var(--color-brand)]",
      value: "text-[var(--color-brand)]",
    },
    sky: {
      glow: "bg-[#38bdf8]",
      value: "text-[#38bdf8]",
    },
    amber: {
      glow: "bg-[#fbbf24]",
      value: "text-[#fbbf24]",
    },
  };

  const toneCfg = toneClasses[tone];

  return (
    <div
      className={`bg-[var(--color-surface)] border border-[var(--color-border-subtle)] rounded-2xl p-6 glass-panel relative overflow-hidden group hover:border-[var(--color-border-strong)] transition-all duration-300 animate-[fadeUp_.4s_ease-out_both] ${delayClass[String(delay)] ?? ""}`}
    >
      <div
        className={`absolute top-0 right-0 w-32 h-32 opacity-[0.03] rounded-bl-full group-hover:opacity-[0.06] transition-opacity duration-500 pointer-events-none ${toneCfg.glow}`}
      />
      <div className="text-[12px] text-[var(--color-text-muted)] uppercase tracking-widest font-medium mb-2 relative z-10">
        {label}
      </div>
      <div
        className={`font-[family-name:var(--font-display)] text-[32px] font-light leading-tight tracking-tight relative z-10 ${toneCfg.value}`}
      >
        {value}
      </div>
    </div>
  );
}
